def refine_seeds_with_massif(image, seeds, mask=None):
    from pyFAI.massif import Massif
    massif = Massif(image, mask=mask, median_prefilter=True)
    refined = []
    for seed in seeds:
        try:
            refined.append(massif.nearest_peak(seed))
        except Exception:
            pass
    return refined
